custom_css:
:root {
    --top-bar-bg: rgba(24, 20, 18, 0.75);
    --topBarBlockSize: 25px;

    --tint-base: rgba(36, 30, 26, 0.92);
    --tint-soft: rgba(58, 48, 42, 0.55);
    --tint-highlight: rgba(196, 168, 130, 0.08);

    --accent-gold: rgba(196, 168, 130, 0.9);
    --accent-muted: rgba(160, 140, 115, 0.6);
}

/* === Typography === */
body {
    font-family: "Inter", "Segoe UI", "Noto Sans", system-ui, sans-serif;
    letter-spacing: 0.01em;
    font-size: 0.9rem;
}

.mes {
    font-size: 1rem;
}

/* === Borders === */
#send_form,
.drawer-content,
.popup[open],
.menu_button,
.drawer-content select,
input,
.select2-container .select2-selection--multiple,
.inline-drawer-content,
textarea,
#extensions_settings .inline-drawer-toggle.inline-drawer-header,
#extensions_settings2 .inline-drawer-toggle.inline-drawer-header,
#user-settings-block h4,
.standoutHeader {
    border-radius: 0px !important;
}

/* === Background System === */
#right-nav-panel,
#left-nav-panel,
#top-bar {
    background:
        linear-gradient(180deg, var(--tint-highlight), transparent 50%),
        var(--tint-base) !important;
}

/* === Buttons === */
.menu_button,
.buttons_block .menu_button {
    background: none !important;
    border: none !important;
    opacity: 0.35;
    transition: opacity 0.2s ease, transform 0.1s ease;
}

.menu_button:hover {
    opacity: 0.9;
}

.menu_button:active {
    transform: scale(0.96);
}

/* === Icon Overrides === */
.inline-drawer-icon.fa-circle-chevron-down::before {
    content: "\f078" !important;
    font-family: "Font Awesome 6 Free" !important;
    font-weight: 900 !important;
}

.inline-drawer-icon.fa-circle-chevron-up::before {
    content: "\f077" !important;
    font-family: "Font Awesome 6 Free" !important;
    font-weight: 900 !important;
}

#character_cross.fa-circle-xmark::before,
.fa-circle-xmark::before {
    content: "\f00d" !important;
    font-family: "Font Awesome 6 Free" !important;
    font-weight: 900 !important;
}


/* === Headers === */
#extensions_settings .inline-drawer-toggle.inline-drawer-header,
#extensions_settings2 .inline-drawer-toggle.inline-drawer-header,
#user-settings-block h4,
.standoutHeader {
    background:
        linear-gradient(90deg, rgba(196,168,130,0.12), transparent 60%),
        rgba(0,0,0,0.15);
    color: var(--accent-gold);
    letter-spacing: 0.04em;
}

/* === Inputs === */
input[type='checkbox'] {
    -webkit-appearance: none;
    appearance: none;
    width: 1.2em;
    height: 1.2em;
    border-radius: 3px;
    background-color: var(--tint-soft);
    border: 2px solid var(--accent-muted);
    display: grid;
    place-content: center;
    cursor: pointer;
    transition: all 0.15s ease;
}

input[type='checkbox']:checked {
    background-color: var(--accent-gold);
}

input[type="range"] {
    -webkit-appearance: none;
    appearance: none;
    height: 2px;
    background: var(--SmartThemeUnderlineColor);
    border: none;
}

input[type="range"]::-webkit-slider-thumb {
    -webkit-appearance: none;
    width: 10px;
    height: 10px;
    background: var(--SmartThemeQuoteColor);
    border: none;
}

input.neo-range-slider[type="range"] {
    -webkit-appearance: none !important;
    appearance: none !important;
    width: 100%;
    height: 6px;
    background: rgba(255,255,255,0.06);
    border: 1px solid var(--SmartThemeBorderColor);
    cursor: pointer;
}

input.neo-range-slider[type="range"]::-webkit-slider-runnable-track {
    height: 6px;
    background: transparent;
}

input.neo-range-slider[type="range"]::-webkit-slider-thumb {
    -webkit-appearance: none !important;
    width: 10px;
    height: 10px;
    margin-top: -2px;
    border-radius: 50%;
    background: var(--SmartThemeQuoteColor);
    border: 1px solid rgba(255,255,255,0.25);
    cursor: pointer;
}

input.neo-range-slider[type="range"]::-moz-range-thumb {
    width: 14px;
    height: 14px;
    border-radius: 50%;
    background: var(--SmartThemeQuoteColor);
    border: 1px solid rgba(255,255,255,0.25);
    cursor: pointer;
}

/* === Scrollbars === */
::-webkit-scrollbar {
    width: 6px;
    height: 6px;
}

::-webkit-scrollbar-thumb {
    background-color: var(--accent-muted);
}

::-webkit-scrollbar-thumb:hover {
    background-color: var(--accent-gold);
}

/* === SVG Icon System === */
.drawer-icon.fa-solid::before,
#options_button::before,
#extensionsMenuButton::before,
#mes_impersonate::before,
#mes_continue::before,
#send_but::before,
#stscript_continue i::before,
#stscript_pause i::before,
#stscript_stop i::before,
#mes_stop i::before,
#vm-continue-chat-btn i::before {
    content: "";
    display: inline-block;
    width: 1em;
    height: 1em;
    background-color: currentColor;
    -webkit-mask: var(--icon) no-repeat center / contain;
    mask: var(--icon) no-repeat center / contain;
}

#leftNavDrawerIcon { --icon: url("https://api.iconify.design/pepicons-print/sliders.svg"); }
#API-status-top { --icon: url("https://api.iconify.design/pepicons-print/contract.svg"); }
.drawer-icon[title="AI Response Formatting"] { --icon: url("https://api.iconify.design/pepicons-print/menu.svg"); }
#WIDrawerIcon { --icon: url("https://api.iconify.design/pepicons-print/planet.svg"); }
.drawer-icon[title="User Settings"] { --icon: url("https://api.iconify.design/pepicons-print/eye-frame.svg"); }
#backgrounds-drawer-toggle .drawer-icon { --icon: url("https://api.iconify.design/pepicons-print/photo.svg"); }
.drawer-icon[title="Extensions"],
#extensionsMenuButton { --icon: url("https://api.iconify.design/pepicons-print/stars.svg"); }
.drawer-icon[title="Persona Management"],
#mes_impersonate { --icon: url("https://api.iconify.design/pepicons-print/person.svg"); }
#rightNavDrawerIcon { --icon: url("https://api.iconify.design/pepicons-print/heart-filled.svg"); }
#options_button { --icon: url("https://api.iconify.design/pepicons-print/menu.svg"); }
#mes_continue { --icon: url("https://api.iconify.design/pepicons-print/arrow-right.svg"); }
#send_but { --icon: url("https://api.iconify.design/pepicons-print/paper-plane.svg"); }
#stscript_continue i { --icon: url("https://api.iconify.design/pepicons-print/play.svg"); }
#stscript_pause i { --icon: url("https://api.iconify.design/pepicons-print/pause.svg"); }
#stscript_stop i,
#mes_stop i { --icon: url("https://api.iconify.design/pepicons-print/times.svg"); }
#vm-continue-chat-btn i { --icon: url("https://api.iconify.design/pepicons-print/fast-forward.svg"); }
#vm-topbar-btn { --icon: url("https://api.iconify.design/ph/flower-lotus-duotone.svg"); }

/* === Tags === */
.tag {
    border-radius: 2px !important;
    padding: 2px 6px;
    font-size: 11px;
    letter-spacing: 0.04em;
    border: 1px solid rgba(255,255,255,0.12);
    box-shadow: inset 0 0 0 999px rgba(0,0,0,0.15);
    transition: all 0.15s ease;
}

.tag_name {
    color: rgba(255,255,255,0.9);
}

.tag:hover {
    box-shadow: inset 0 0 0 999px rgba(0,0,0,0.05), 0 0 4px rgba(0,0,0,0.4);
    border-color: rgba(255,255,255,0.2);
}

.tag:active {
    transform: scale(0.96);
}

/* === World Info === */
.world_entry {
    margin-bottom: 6px;
}

.wi-card-entry {
    background: rgba(0, 0, 0, 0.35);
    border: 1px solid var(--SmartThemeBorderColor);
    border-radius: 2px !important;
    overflow: hidden;
    transition: border-color 0.2s ease, box-shadow 0.2s ease;
}

.wi-card-entry:hover {
    border-color: rgba(255,255,255,0.18);
    box-shadow: 0 0 6px rgba(0,0,0,0.5);
}

.WIEntryTitleAndStatus textarea.text_pole {
    background: transparent;
    border: none;
    font-weight: 500;
    font-size: 13px;
    color: var(--SmartThemeMainTextColor);
}

.WIEntryTitleAndStatus textarea.text_pole:focus {
    outline: none;
    border-bottom: 1px solid var(--SmartThemeQuoteColor);
}

.inline-drawer-toggle {
    opacity: 0.5;
    transition: opacity 0.2s ease;
}

.inline-drawer-toggle:hover {
    opacity: 1;
}

/* ===== REASONING BLOCK ===== */

.mes_reasoning_header {
    background: rgba(255,255,255,0.04);
    border: 1px solid rgba(255,255,255,0.08);
    border-radius: 6px;

    font-family: var(--font-body);
    font-size: 0.9em;
    letter-spacing: 0.3px;

    padding: 6px 20px;
}

/* main reasoning content */
.mes_reasoning {
    font-family: var(--font-mono);

    background: rgba(0,0,0,0.25);
    border: 1px solid rgba(255,255,255,0.06);
    border-top: none;

    border-radius: 0 0 6px 6px;
    padding: 10px 12px;

    font-size: 0.9em;
    line-height: 1.5;

    color: rgba(220, 235, 235, 0.85);
}

/* optional: subtle divider when collapsed/expanded */
.mes_reasoning_header + .mes_reasoning {
    margin-top: -1px;
}

/* optional: make code inside reasoning even cleaner */
.mes_reasoning code {
    background: rgba(255,255,255,0.04);
    border-radius: 4px;
    padding: 2px 4px;
}

/* === Toasts === */
.toast {
    background-color: rgba(28, 24, 20, 0.96) !important;
    color: rgba(235, 225, 210, 0.92) !important;
    border: 1px solid rgba(196, 168, 130, 0.25) !important;
    border-left: 4px solid var(--accent-gold) !important;
    box-shadow: 0 6px 14px rgba(0, 0, 0, 0.5) !important;
}

.toast::before {
    content: "";
    position: absolute;
    inset: 0;
    background: linear-gradient(135deg, rgba(196,168,130,0.08), transparent 50%);
    pointer-events: none;
}

.toast-title {
    font-weight: 600;
    font-size: 12px;
    text-transform: uppercase;
    letter-spacing: 0.08em;
    border-bottom: 1px dashed rgba(196,168,130,0.3);
}

.toast-message {
    font-size: 13px;
    line-height: 1.4;
}
